pyb::object AddActuatorByKind(pyb::object self, const std::string& kind,
                 const pyb::kwargs& kw) {
  Model& m = self.cast<Model&>();
  if (kind == "general")
    return FinishChild(self, ps::sdk::AddActuator<ActuatorGeneral>(m), kw);
  if (kind == "motor")
    return FinishChild(self, ps::sdk::AddActuator<Motor>(m), kw);
  if (kind == "position")
    return FinishChild(self, ps::sdk::AddActuator<Position>(m), kw);
  if (kind == "velocity")
    return FinishChild(self, ps::sdk::AddActuator<Velocity>(m), kw);
  if (kind == "intvelocity")
    return FinishChild(self, ps::sdk::AddActuator<IntVelocity>(m), kw);
  if (kind == "orientation")
    return FinishChild(self, ps::sdk::AddActuator<Orientation>(m), kw);
  if (kind == "damper")
    return FinishChild(self, ps::sdk::AddActuator<Damper>(m), kw);
  if (kind == "cylinder")
    return FinishChild(self, ps::sdk::AddActuator<Cylinder>(m), kw);
  if (kind == "muscle")
    return FinishChild(self, ps::sdk::AddActuator<Muscle>(m), kw);
  if (kind == "adhesion")
    return FinishChild(self, ps::sdk::AddActuator<Adhesion>(m), kw);
  if (kind == "dcmotor")
    return FinishChild(self, ps::sdk::AddActuator<DcMotor>(m), kw);
  if (kind == "plugin")
    return FinishChild(self, ps::sdk::AddActuator<ActuatorPlugin>(m), kw);
  throw pyb::value_error("unknown actuator kind '" + kind +
                         "' (general/motor/position/velocity/intvelocity/orientation/damper/cylinder/muscle/adhesion/dcmotor/plugin)");
}

