  if (kind == "tendonlimitvel")
    return FinishChild(self, ps::sdk::AddSensor<Tendonlimitvel>(m), kw);
  if (kind == "tendonlimitfrc")
    return FinishChild(self, ps::sdk::AddSensor<Tendonlimitfrc>(m), kw);
